/**
 * jit-worker.js — Module Web Worker for JIT CSS generation.
 *
 * Imports the shared pipeline from jit-pipeline.js so the worker
 * stays in sync with the main thread without Function.prototype.toString().
 *
 * Protocol:
 *   Main -> Worker:  { id, classes: string[], stepCfg, scale }
 *   Worker -> Main:  { id, results: { cls, css }[], stepRules: string[] }
 */

import {
    setColorScale,
    setStepConfig,
    setEnsureStepVar,
    resolveStep,
    resolveStepDark,
    generate,
    registerHandlers,
    COLOR_HUES,
} from '../core/jit-pipeline.js';

// ===============================================
//  Worker-local state
// ===============================================

const HANDLERS = new Map();
registerHandlers(HANDLERS);

// Worker-side step variable generation:
// No DOM here — collect rules and send back to main thread for injection.
const _stepVarsEmitted = new Set();
let _pendingStepRules = [];

function workerEnsureStepVar(colorName, step, hue) {
    const key = `${colorName}-${step}`;
    if (_stepVarsEmitted.has(key)) return;
    _stepVarsEmitted.add(key);
    const { s, l } = resolveStep(step);
    const { s: ds, l: dl } = resolveStepDark(step);
    _pendingStepRules.push(
        `:root{--cs-${key}:hsl(${hue},${s}%,${l}%)}`,
        `[data-theme="dark"]{--cs-${key}:hsl(${hue},${ds}%,${dl}%)}`,
        `@media(prefers-color-scheme:dark){:root:not([data-theme="light"]){--cs-${key}:hsl(${hue},${ds}%,${dl}%)}}`
    );
}

setEnsureStepVar(workerEnsureStepVar);

// ===============================================
//  Message handler
// ===============================================

self.onmessage = function (e) {
    const { id, type, classes, stepCfg, scale } = e.data;

    // Sync mutable state from main thread
    if (stepCfg) setStepConfig(stepCfg);
    if (scale !== undefined) setColorScale(scale);

    // Config-only update (no classes to process)
    if (type === 'configUpdate') return;

    _pendingStepRules = [];

    const results = [];
    for (const cls of classes) {
        const css = generate(cls, HANDLERS);
        results.push({ cls, css });
    }

    self.postMessage({ id, results, stepRules: _pendingStepRules.slice() });
};
